import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/macos-downloads.DCRwPSpe.js";const o=JSON.parse(`{"title":"Fabric 설치","description":"Fabric을 설치하는 방법에 대한 단계별 가이드입니다.","frontmatter":{"title":"Fabric 설치","description":"Fabric을 설치하는 방법에 대한 단계별 가이드입니다.","authors":["IMB11","Benonardo","modmuss50"],"files":[]},"headers":[],"relativePath":"ko_kr/1.21.1/players/installing-fabric.md","filePath":"versions/1.21.1/translated/ko_kr/players/installing-fabric.md","lastUpdated":1761424914000}`);var s={name:`ko_kr/1.21.1/players/installing-fabric.md`};function c(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Fabric 설치 <a class="header-anchor" href="#h1" aria-label="Permalink to “Fabric 설치”">​</a></h1><p>이 가이드는 오직 공식 Minecraft 런처용 Fabric 설치 방법을 안내합니다. 서드 파티 런처의 경우, 해당 런처의 설명서를 참조하여 주세요.</p><h2 id="1-download-the-fabric-installer" tabindex="-1">1. Fabric 실행기 다운로드하기 <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. Fabric 실행기 다운로드하기”">​</a></h2><p><a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">Fabric 웹사이트</a>에서 Fabric 실행기를 설치할 수 있습니다.</p><p>Windows라면, Java가 다운로드 되어야 할 필요가 없게 하도록 <code>exe</code> 버전 (<code>Windows 용 다운로드</code>)를 다운로드하세요. 대신 공식 런처와 함께 제공되는 Java를 사용합니다.</p><p>macOS나 Linux의 경우라면, <code>.jar</code>버전을 다운로드 받으셔야 합니다. 가끔, 이 단계 전에 Java를 다운로드하셔야 할 때도 있습니다.</p><h2 id="2-run-the-fabric-installer" tabindex="-1">2. Fabric 실행기 실행하기 <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. Fabric 실행기 실행하기”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>실행하기 전, 먼저 Minecraft와 Minecraft 런처를 닫으세요.</p></div><details class="details custom-block"><summary>macOS 사용자들을 위한 정보</summary><p>macOS의 경우 다운로드 디렉터리에서 &#39;.jar&#39; 파일을 마우스 오른쪽 버튼으로 클릭하고 &#39;열기&#39;를 클릭하여 실행해야 할 수 있습니다.</p><p><img src="/assets/players/installing-fabric/macos-downloads.png" alt="Fabric 실행기의 MacOS 컨텍스트 메뉴" loading="lazy"></p><p>&quot;여시겠습니까&quot;?라고 물으면, <code>열기</code>를 한 번 더 클릭하세요.</p></details><p>설치기를 열면, 다음과 같은 화면이 보일 것입니다:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="&quot;Install&quot;을 강조 표시한 Fabric 설치기" loading="lazy"></p><p>Fabric을 설치하기 위하여 드롭다운에서 게임 버전을 선택하고 <code>install</code>을 클릭하세요.</p><div class="warning custom-block"><p class="custom-block-title">중요</p><p>&#39;Create Profile&#39;이 켜져 있는지 확인하세요.</p></div><h2 id="3-you-re-done" tabindex="-1">3. 이제 끝났습니다! <a class="header-anchor" href="#3-you-re-done" aria-label="Permalink to “3. 이제 끝났습니다!”">​</a></h2><p>설치가 완료되면 Minecraft 런처를 열고 왼쪽 하단의 드롭다운에서 Fabric 프로필을 선택한 후 플레이를 누르면 됩니다!</p><p>![Fabric 프로필을 선택한 Minecraft 런처](/assets/플레이어/설치-패브릭/런처 화면.png)</p><p>이제 Fabric을 설치했으니 게임에 모드를 추가할 수 있습니다! <a href="./finding-mods">안전한 모드 찾기</a> 에서 더 많은 정보를 확인할 수 있습니다.</p><p>이 가이드를 따르는 동안 문제가 발생하면 <code>#player-support</code> 채널의 <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Fabric Discord</a>에서 도움을 요청할 수 있습니다.</p>`,18)]])}var l=r(s,[[`render`,c]]);export{o as __pageData,l as default};